const ERC20_CONTRACTS_BY_SYMBOL = (function() {
    const map = {};
    for (let i = 0; i < ERC20_CONTRACTS_RAW.length; i++) {
        const entry = ERC20_CONTRACTS_RAW[i],
            sym = entry.symbol;
        map[sym] = entry;
    }
    return map;
})();

// Look up an ERC-20 contract by symbol.
function contracts(ccsymbol, network) {
    if (!ccsymbol) {
        return false;
    }
    if (ccsymbol === "br_all") {
        return ERC20_CONTRACTS_RAW;
    }
    const entry = ERC20_CONTRACTS_BY_SYMBOL[ccsymbol];
    if (!entry) {
        return false;
    }
    if (network) {
        return entry.contract;
    }
    return entry;
}